class CosmosQuery
{
    async Task FindProducts(ProductContext ctx)
    {
        // Direct Cosmos SQL — safe because we preserved "Discriminator" via HasDiscriminator().
        // If we had NOT configured this, EF Core 9 would use "$type" for new documents
        // while existing documents still have "Discriminator", breaking this query.
        var sql = "SELECT * FROM c WHERE c.Discriminator = 'Product' AND c.Sku = @sku";

        // EF Core 9 Cosmos provider no longer supports synchronous I/O.
        // ToList() now throws; use ToListAsync() instead.
        var products = await ctx.Products.Where(p => p.Sku == "ABC").ToListAsync();
    }
}

